"""Tests for check-placeholders.py placeholder contract audit."""
import dataclasses
import importlib.util
import io
import json
import pathlib
import tempfile
import textwrap
import unittest
from unittest.mock import patch

# Import the module under test (hyphenated filename requires importlib)
_spec = importlib.util.spec_from_file_location(
    "check_placeholders",
    pathlib.Path(__file__).with_name("check-placeholders.py"),
)
check_placeholders = importlib.util.module_from_spec(_spec)
_spec.loader.exec_module(check_placeholders)


class TestHelpers(unittest.TestCase):
    """Test helper functions."""

    def test_extract_feature_hint_from_line(self):
        hint = check_placeholders.extract_feature_hint(
            [], 'fmt.Fprintln(os.Stderr, "flotsam voice: not yet implemented")'
        )
        self.assertEqual(hint, "voice")

    def test_extract_feature_hint_from_context(self):
        context = ["func voiceCmd() *ucli.Command {"]
        hint = check_placeholders.extract_feature_hint(context, "return nil")
        self.assertEqual(hint, "voice")

    def test_extract_feature_hint_no_match(self):
        hint = check_placeholders.extract_feature_hint([], "return nil")
        self.assertEqual(hint, "")

    def test_extract_feature_hints_from_line(self):
        hints = check_placeholders.extract_feature_hints_from_line(
            "MCP server is implemented with JWT auth"
        )
        self.assertIn("mcp", hints)
        self.assertIn("auth", hints)

    def test_extract_feature_hints_no_match(self):
        hints = check_placeholders.extract_feature_hints_from_line(
            "The system is configured properly."
        )
        self.assertEqual(hints, [])

    def test_is_excluded_test_file(self):
        self.assertTrue(check_placeholders._is_excluded("api/internal/item/service_test.go"))

    def test_is_excluded_generated(self):
        self.assertTrue(check_placeholders._is_excluded("api/graph/generated/generated.go"))

    def test_is_not_excluded_normal(self):
        self.assertFalse(check_placeholders._is_excluded("api/internal/item/service.go"))

    def test_is_in_handler_dir(self):
        self.assertTrue(check_placeholders._is_in_handler_dir("api/graph/resolver/schema.resolvers.go"))
        self.assertTrue(check_placeholders._is_in_handler_dir("api/cmd/flotsamd/main.go"))

    def test_is_not_in_handler_dir(self):
        self.assertFalse(check_placeholders._is_in_handler_dir("api/internal/item/service.go"))

    def test_has_qualifier_positive(self):
        self.assertTrue(check_placeholders._has_qualifier("not yet implemented"))
        self.assertTrue(check_placeholders._has_qualifier("will be available soon"))

    def test_has_qualifier_negative(self):
        self.assertFalse(check_placeholders._has_qualifier("MCP server is implemented"))


class TestScanCodePlaceholders(unittest.TestCase):
    """Test Go source placeholder scanning."""

    def _make_repo(self, files: dict[str, str]) -> pathlib.Path:
        """Create a temp repo structure. files maps relative paths to content."""
        tmpdir = tempfile.mkdtemp()
        root = pathlib.Path(tmpdir)
        for rel_path, content in files.items():
            full = root / rel_path
            full.parent.mkdir(parents=True, exist_ok=True)
            full.write_text(content, encoding="utf-8")
        return root

    def test_detects_not_implemented_string(self):
        root = self._make_repo({
            "api/cmd/flotsam/main.go": textwrap.dedent("""\
                package main

                func voiceCmd() {
                    fmt.Fprintln(os.Stderr, "flotsam voice: not yet implemented")
                }
            """),
        })
        results = check_placeholders.scan_code_placeholders(root)
        self.assertEqual(len(results), 1)
        self.assertEqual(results[0].category, "not_implemented")
        self.assertEqual(results[0].feature_hint, "voice")
        self.assertIn("not yet implemented", results[0].text)

    def test_detects_status_not_implemented(self):
        root = self._make_repo({
            "api/internal/handler/upload.go": textwrap.dedent("""\
                package handler

                func Upload(w http.ResponseWriter, r *http.Request) {
                    w.WriteHeader(http.StatusNotImplemented)
                }
            """),
        })
        results = check_placeholders.scan_code_placeholders(root)
        self.assertEqual(len(results), 1)
        self.assertEqual(results[0].category, "http_501")

    def test_detects_coming_soon(self):
        root = self._make_repo({
            "api/cmd/flotsam/main.go": textwrap.dedent("""\
                package main

                func searchCmd() {
                    fmt.Println("Search: coming soon")
                }
            """),
        })
        results = check_placeholders.scan_code_placeholders(root)
        cats = [r.category for r in results]
        self.assertIn("coming_soon", cats)

    def test_detects_todo_in_handler_dir(self):
        root = self._make_repo({
            "api/graph/resolver/schema.resolvers.go": textwrap.dedent("""\
                package resolver

                func (r *queryResolver) Items() {
                    // TODO: implement pagination
                    return nil, nil
                }
            """),
        })
        results = check_placeholders.scan_code_placeholders(root)
        cats = [r.category for r in results]
        self.assertIn("todo_in_handler", cats)

    def test_ignores_todo_in_non_handler(self):
        root = self._make_repo({
            "api/internal/item/service.go": textwrap.dedent("""\
                package item

                // TODO: optimize this later
                func Search() {}
            """),
        })
        results = check_placeholders.scan_code_placeholders(root)
        cats = [r.category for r in results]
        self.assertNotIn("todo_in_handler", cats)

    def test_excludes_generated_code(self):
        root = self._make_repo({
            "api/graph/generated/generated.go": textwrap.dedent("""\
                package generated

                // not yet implemented
                panic("not implemented")
            """),
        })
        results = check_placeholders.scan_code_placeholders(root)
        self.assertEqual(results, [])

    def test_excludes_test_files(self):
        root = self._make_repo({
            "api/internal/item/service_test.go": textwrap.dedent("""\
                package item

                // not yet implemented
                func TestSomething() {}
            """),
        })
        results = check_placeholders.scan_code_placeholders(root)
